const rows = $input.all();
if (rows.length === 0 || !rows[0].json.search_name) {
  return [{ json: { text: 'No monitored searches or events found.', event_ids: [], ref_map: {} } }];
}

const categories = {};
const eventIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const category = data.search_name;
  if (!categories[category]) {
    categories[category] = [];
  }
  if (data.id) {
    eventIds.add(data.id);
    categories[category].push({
      id: data.id,
      title: data.title,
      description: data.description,
      url: data.url,
      published_at: data.published_at
    });
  }
});

const refMap = {};
let refCounter = 1;

let text = 'Meetup events to summarize (each has an id number):\n\n';

for (const [category, events] of Object.entries(categories)) {
  if (events.length === 0) continue;

  text += `Category: ${category}\n`;
  events.forEach(event => {
    const refId = refCounter++;
    refMap[String(refId)] = { title: event.title || 'Event', url: event.url || '', category: category };

    text += `  id:${refId} | ${event.title || 'No Title'} (at ${event.published_at || 'unknown'})\n`;
    text += `  Description: ${(event.description || '').substring(0, 500)}\n\n`;
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/bella.md', 'utf8');
} catch (e) {
  persona = 'Warm, charming Italian secretary named Bella.';
}

let strategy = '';
try {
  strategy = fs.readFileSync('/etc/n8n/workflows/prompts/content_strategy.md', 'utf8');
} catch (e) {
  strategy = '';
}

let positioning = '';
try {
  positioning = fs.readFileSync('/etc/n8n/workflows/prompts/usp_market_positioning.md', 'utf8');
} catch (e) {
  positioning = '';
}

return [{ json: { text, event_ids: Array.from(eventIds), ref_map: refMap, bella_persona: persona, content_strategy: strategy, usp_positioning: positioning } }];

