const raw = $input.first().json.content || $input.first().json.response || '';
const refMap = $('Format Events for LLM').first().json.ref_map || {};

let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    const cleanedStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(cleanedStr);
  } catch (err) {
    return [{ json: { response: raw } }];
  }
}

const greeting = parsed.greeting || '';
const signoff = parsed.signoff || '';
const summaries = Array.isArray(parsed.summaries) ? parsed.summaries : [];

const summaryMap = {};
summaries.forEach(s => {
  if (s.event_id) {
    summaryMap[String(s.event_id)] = s.summary;
  }
});

const categories = {};
for (const [id, ref] of Object.entries(refMap)) {
  const category = ref.category || 'Other';
  if (!categories[category]) {
    categories[category] = [];
  }
  const summary = summaryMap[id] || 'No summary available.';
  categories[category].push({
    title: ref.title,
    url: ref.url,
    summary: summary
  });
}

let msg = '';
if (greeting) msg += `${greeting}\n\n`;
msg += '✨ *Weekly Meetup Events Summary* ✨\n\n';

let count = 0;
for (const [category, events] of Object.entries(categories)) {
  if (events.length === 0) continue;
  msg += `*${category}*\n`;
  events.forEach(event => {
    msg += `• <${event.url}|${event.title}>: ${event.summary}\n`;
    count++;
  });
  msg += '\n';
}

if (count === 0) {
  msg += 'No new events scheduled for this week.\n\n';
}

if (signoff) msg += `${signoff}`;

return [{ json: { response: msg.trim() } }];
